    def pop(self):
        return self.data.pop()

class RingBuffer:
    def __init__(self, capacity):
        self.buf = [None] * capacity
        self.head = 0
        self.tail = 0
        self.count = 0
    def enqueue(self, value):
        if self.count == len(self.buf):
            raise OverflowError
        self.buf[self.tail] = value
        self.tail = (self.tail + 1) % len(self.buf)
        self.count += 1
    def dequeue(self):
        if self.count == 0:
            raise IndexError
        value = self.buf[self.head]
        self.head = (self.head + 1) % len(self.buf)
        self.count -= 1
        return value

class SimpleHashMap:
    def __init__(self, capacity=8):
        self.buckets = [[] for _ in range(capacity)]
        self.size = 0
    def put(self, key, value):
        bucket = self.buckets[hash(key) % len(self.buckets)]
        for idx, (k, _) in enumerate(bucket):
            if k == key:
                bucket[idx] = (key, value)
                return
        bucket.append((key, value))
        self.size += 1

from collections import deque

def sliding_window_max(arr, k):
    dq = deque()
    for i, value in enumerate(arr):
        while dq and arr[dq[-1]] < value:
            dq.pop()
        dq.append(i)
        if dq[0] == i - k:
            dq.popleft()
        if i >= k - 1:
            yield arr[dq[0]]

def lis(arr):
    n = len(arr)
    dp = [1] * n
    for i in range(n):
        for j in range(i):
            if arr[j] < arr[i]:
                dp[i] = max(dp[i], dp[j] + 1)
    return max(dp, default=0)

def best_profit(intervals):
    intervals.sort(key=lambda x: x[1])
    memo = {}
    def helper(i):
        if i == len(intervals):
            return 0
        if i in memo:
            return memo[i]
        start, end, weight = intervals[i]
        j = i + 1
        while j < len(intervals) and intervals[j][0] < end:
            j += 1
        include = helper(j) + weight
        exclude = helper(i + 1)
        memo[i] = max(include, exclude)
        return memo[i]
    return helper(0)

import random

def quickselect(arr, k):
    if len(arr) == 1:
        return arr[0]
    pivot = random.choice(arr)
    lows = [x for x in arr if x < pivot]
    highs = [x for x in arr if x > pivot]
    pivots = [x for x in arr if x == pivot]
    if k < len(lows):
        return quickselect(lows, k)
    if k < len(lows) + len(pivots):
        return pivot
    return quickselect(highs, k - len(lows) - len(pivots))

from collections import deque

def multi_source_dist(adj, starts):
    dist = {s: 0 for s in starts}
    q = deque(starts)
    while q:
        u = q.popleft()
        for v in adj[u]:
            if v not in dist:
                dist[v] = dist[u] + 1
                q.append(v)
    return dist

